#!/usr/bin/env python3\nimport redis\nimport sys\nimport json\nfrom redis.commands.search.query import Query\nr = redis.Redis(host='localhost', port=6379, db=0, decode_responses=True)\nif len(sys.argv) &lt; 2:\n    print(json.dumps({\"error\": \"Query required\"}))\n    sys.exit(1)\nquery = sys.argv[1]\n# Simple keyword search (future: FT.SEARCH)\nkeys = r.keys('memory:*')\nresults = []\nfor key in keys:\n    content = r.get(key)\n    if content and query.lower() in content.lower():\n        results.append({\"key\": key, \"snippet\": content[:500]})\nif results:\n    print(json.dumps(results[:5]))\nelse:\n    print(json.dumps([]))